/**
 * BriefExportPage — Multi-select strategy cards and export as .xlsx brief.
 *
 * Features:
 * - Checkbox list: select strategies to export (default: all confirmed)
 * - Export config: format (Excel default), field toggles
 * - Preview area: multi-sheet table preview
 * - Download button → generates .xlsx
 * - Filename: {品牌名}_投放Brief_{日期}.xlsx
 */
import React, { useMemo, useState, useCallback } from 'react';
import {
  Box,
  Typography,
  Checkbox,
  FormControlLabel,
  FormGroup,
  Button,
  Card,
  CardContent,
  Divider,
  Alert,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Chip,
  Stack,
  ToggleButtonGroup,
  ToggleButton,
  CircularProgress,
} from '@mui/material';
import DownloadIcon from '@mui/icons-material/Download';
import PreviewIcon from '@mui/icons-material/Preview';
import { useBrandStore } from '@/shared/stores/brandStore';
import { db } from '@/shared/db/db';
import { useLiveQuery } from 'dexie-react-hooks';
import { downloadBrief, buildBriefPreview, type BriefPreviewSheet } from '@/shared/utils/brief';
import type { StrategyCard } from '@/shared/types/strategy';

interface FieldToggle {
  key: string;
  label: string;
  checked: boolean;
}

const BriefExportPage: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const currentBrand = useBrandStore((s) => {
    const { brands, currentBrandId: cid } = s;
    return brands.find((b) => b.id === cid) ?? null;
  });

  const allCards = useLiveQuery(
    () =>
      currentBrandId
        ? db.strategyCards.where({ brandId: currentBrandId }).toArray()
        : Promise.resolve([] as StrategyCard[]),
    [currentBrandId],
  );

  const cards = allCards ?? [];

  // Default: select all confirmed
  const [selectedIds, setSelectedIds] = useState<Set<string>>(() => {
    const confirmed = cards.filter((c) => c.reviewStatus === 'confirmed');
    return new Set(confirmed.map((c) => c.id));
  });

  const [fieldToggles, setFieldToggles] = useState<FieldToggle[]>([
    { key: 'title', label: '策略标题', checked: true },
    { key: 'evidence', label: '评论证据', checked: true },
    { key: 'contentDirection', label: '内容方向', checked: true },
    { key: 'abTestVariables', label: '测试变量', checked: true },
    { key: 'expectedKPIs', label: '预期KPI', checked: true },
    { key: 'budgetSuggestion', label: '预算建议', checked: true },
  ]);

  const [previewMode, setPreviewMode] = useState(false);

  const selectedCards = useMemo(
    () => cards.filter((c) => selectedIds.has(c.id)),
    [cards, selectedIds],
  );

  const previewData: BriefPreviewSheet[] = useMemo(
    () => buildBriefPreview(selectedCards),
    [selectedCards],
  );

  const handleToggleAll = useCallback(() => {
    if (selectedIds.size === cards.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(cards.map((c) => c.id)));
    }
  }, [cards, selectedIds]);

  const handleToggleCard = useCallback((id: string) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }, []);

  const handleToggleField = useCallback((key: string) => {
    setFieldToggles((prev) =>
      prev.map((f) => (f.key === key ? { ...f, checked: !f.checked } : f)),
    );
  }, []);

  const handleExport = useCallback(() => {
    const brandName = currentBrand?.name ?? '未命名品牌';
    downloadBrief(selectedCards, brandName);
  }, [selectedCards, currentBrand]);

  const selectedConfirmed = selectedCards.filter((c) => c.reviewStatus === 'confirmed').length;
  const selectedPending = selectedCards.filter((c) => c.reviewStatus === 'pending').length;

  if (!currentBrandId) {
    return (
      <Box sx={{ p: 4, textAlign: 'center' }}>
        <Alert severity="info">请先在顶部选择一个品牌</Alert>
      </Box>
    );
  }

  if (allCards === undefined) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', py: 8 }}>
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box sx={{ p: 3, maxWidth: 1200, mx: 'auto' }}>
      {/* Header */}
      <Typography variant="h5" fontWeight={700} gutterBottom>
        📋 Brief 导出
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        多选策略卡，生成多 Sheet 的 .xlsx 投放 Brief
      </Typography>

      {cards.length === 0 ? (
        <Alert severity="warning">
          当前品牌暂无策略卡。请先前往 AI 工作台生成策略。
        </Alert>
      ) : (
        <Box sx={{ display: 'flex', gap: 3, flexDirection: { xs: 'column', lg: 'row' } }}>
          {/* Left: Selection */}
          <Box sx={{ flex: 1, minWidth: 0 }}>
            <Card sx={{ mb: 2 }}>
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
                  <Typography variant="subtitle1" fontWeight={600}>
                    选择策略卡 ({selectedIds.size}/{cards.length})
                  </Typography>
                  <Button size="small" onClick={handleToggleAll}>
                    {selectedIds.size === cards.length ? '取消全选' : '全选'}
                  </Button>
                </Box>
                <FormGroup sx={{ maxHeight: 400, overflow: 'auto' }}>
                  {cards.map((card) => (
                    <FormControlLabel
                      key={card.id}
                      control={
                        <Checkbox
                          size="small"
                          checked={selectedIds.has(card.id)}
                          onChange={() => handleToggleCard(card.id)}
                        />
                      }
                      label={
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                          <Chip
                            label={card.priority}
                            size="small"
                            color={card.priority === 'P0' ? 'error' : card.priority === 'P1' ? 'warning' : 'primary'}
                            variant="outlined"
                            sx={{ height: 20, fontSize: 10 }}
                          />
                          <Typography variant="body2" noWrap sx={{ maxWidth: 300 }}>
                            {card.title}
                          </Typography>
                          <Chip
                            label={card.reviewStatus === 'confirmed' ? '已确认' : '待审核'}
                            size="small"
                            color={card.reviewStatus === 'confirmed' ? 'success' : 'warning'}
                            sx={{ height: 18, fontSize: 10, ml: 'auto' }}
                          />
                        </Box>
                      }
                      sx={{ width: '100%' }}
                    />
                  ))}
                </FormGroup>
              </CardContent>
            </Card>

            {/* Selection summary */}
            <Alert severity={selectedPending > 0 ? 'warning' : 'success'} sx={{ mb: 2 }}>
              已勾选 {selectedCards.length} 条策略卡，其中 {selectedConfirmed} 条已确认
              {selectedPending > 0 ? `，${selectedPending} 条待审核` : ''}
            </Alert>

            {/* Field toggles */}
            <Card sx={{ mb: 2 }}>
              <CardContent>
                <Typography variant="subtitle1" fontWeight={600} gutterBottom>
                  导出字段
                </Typography>
                <Stack direction="row" spacing={1} flexWrap="wrap" useFlexGap>
                  {fieldToggles.map((f) => (
                    <FormControlLabel
                      key={f.key}
                      control={
                        <Checkbox
                          size="small"
                          checked={f.checked}
                          onChange={() => handleToggleField(f.key)}
                        />
                      }
                      label={f.label}
                      sx={{ mr: 1 }}
                    />
                  ))}
                </Stack>
              </CardContent>
            </Card>

            {/* Actions */}
            <Stack direction="row" spacing={2}>
              <Button
                variant="contained"
                startIcon={<DownloadIcon />}
                onClick={handleExport}
                disabled={selectedCards.length === 0}
              >
                导出 Excel (.xlsx)
              </Button>
              <Button
                variant="outlined"
                startIcon={<PreviewIcon />}
                onClick={() => setPreviewMode(!previewMode)}
              >
                {previewMode ? '隐藏预览' : '预览 Brief'}
              </Button>
            </Stack>
          </Box>

          {/* Right: Preview */}
          {previewMode && (
            <Box sx={{ flex: 1.5, minWidth: 0 }}>
              <Card>
                <CardContent>
                  <Typography variant="subtitle1" fontWeight={600} gutterBottom>
                    Brief 预览
                  </Typography>
                  <Typography variant="caption" color="text.secondary" sx={{ mb: 2, display: 'block' }}>
                    文件名：{currentBrand?.name ?? '未命名'}_投放Brief_{new Date().toISOString().split('T')[0]}.xlsx
                  </Typography>

                  {previewData.map((sheet, si) => (
                    <Box key={si} sx={{ mb: 3 }}>
                      <Typography variant="subtitle2" fontWeight={600} gutterBottom>
                        Sheet {si + 1}: {sheet.name}
                      </Typography>
                      <TableContainer component={Paper} variant="outlined" sx={{ mb: 1 }}>
                        <Table size="small">
                          <TableHead>
                            <TableRow>
                              <TableCell sx={{ fontWeight: 600, width: 140 }}>字段</TableCell>
                              <TableCell sx={{ fontWeight: 600 }}>内容</TableCell>
                            </TableRow>
                          </TableHead>
                          <TableBody>
                            {sheet.fields.map((f, fi) => (
                              <TableRow key={fi}>
                                <TableCell sx={{ fontWeight: 500, color: 'text.secondary' }}>
                                  {f.label}
                                </TableCell>
                                <TableCell>{f.value || '-'}</TableCell>
                              </TableRow>
                            ))}
                          </TableBody>
                        </Table>
                      </TableContainer>
                      {si < previewData.length - 1 && <Divider sx={{ my: 1 }} />}
                    </Box>
                  ))}
                </CardContent>
              </Card>
            </Box>
          )}
        </Box>
      )}
    </Box>
  );
};

export default BriefExportPage;
