/**
 * Brief Excel export builder.
 * Uses SheetJS (xlsx) to generate multi-sheet workbooks from strategy cards.
 */
import * as XLSX from 'xlsx';
import type { StrategyCard } from '../types/strategy';

/** Build a multi-sheet workbook from selected strategy cards */
export function buildBriefWorkbook(
  strategies: StrategyCard[],
  brandName: string,
): XLSX.WorkBook {
  const wb = XLSX.utils.book_new();

  strategies.forEach((s, i) => {
    const sheetName = `策略${i + 1}_${s.title.substring(0, 20)}`;

    const rows: (string | number)[][] = [
      ['策略标题', s.title],
      ['副标题', s.subtitle ?? ''],
      ['优先级', s.priority],
      ['状态', statusLabel(s.status)],
      ['审核状态', reviewLabel(s.reviewStatus)],
      [''],
      ['评论证据', ...s.evidence],
      [''],
      ['内容方向', s.contentDirection],
      [''],
      [
        'A/B测试变量',
        ...s.abTestVariables.map(
          (v) => `${v.group}组: ${v.direction} | 变量: ${v.variable} | KPI: ${v.kpi}`,
        ),
      ],
      [''],
      ['预期KPI', ...s.expectedKPIs],
      [''],
      ['预算建议', s.budgetSuggestion],
      [''],
      ['人群定向', ...(s.audienceTarget || [])],
    ];

    const ws = XLSX.utils.aoa_to_sheet(rows);

    // Auto-size columns
    const colWidths = rows.reduce((max, row) => {
      row.forEach((cell, ci) => {
        const len = String(cell).length;
        if (!max[ci] || len > max[ci]) max[ci] = len;
      });
      return max;
    }, [] as number[]);
    ws['!cols'] = colWidths.map((w) => ({ wch: Math.min(w + 4, 60) }));

    XLSX.utils.book_append_sheet(wb, ws, sheetName);
  });

  return wb;
}

/** Export workbook as .xlsx download */
export function downloadBrief(
  strategies: StrategyCard[],
  brandName: string,
): void {
  const wb = buildBriefWorkbook(strategies, brandName);
  const dateStr = new Date().toISOString().split('T')[0];
  const filename = `${brandName}_投放Brief_${dateStr}.xlsx`;
  XLSX.writeFile(wb, filename);
}

/** Build a preview data structure for the Brief preview table */
export interface BriefPreviewSheet {
  name: string;
  fields: { label: string; value: string }[];
}

export function buildBriefPreview(strategies: StrategyCard[]): BriefPreviewSheet[] {
  return strategies.map((s, i) => ({
    name: `策略${i + 1}: ${s.title}`,
    fields: [
      { label: '策略标题', value: s.title },
      { label: '副标题', value: s.subtitle ?? '' },
      { label: '优先级', value: s.priority },
      { label: '状态', value: statusLabel(s.status) },
      { label: '内容方向', value: s.contentDirection },
      { label: '预算建议', value: s.budgetSuggestion },
      {
        label: 'A/B测试变量',
        value: s.abTestVariables
          .map((v) => `${v.group}组: ${v.direction}`)
          .join('; '),
      },
      { label: '预期KPI', value: s.expectedKPIs.join(', ') },
      { label: '人群定向', value: (s.audienceTarget || []).join(', ') },
    ],
  }));
}

/** Helper: status label */
function statusLabel(status: string): string {
  switch (status) {
    case 'active':
      return '执行中';
    case 'draft':
      return '草稿';
    case 'archived':
      return '已归档';
    default:
      return status;
  }
}

/** Helper: review label */
function reviewLabel(status: string): string {
  switch (status) {
    case 'confirmed':
      return '已确认';
    case 'pending':
      return '待审核';
    case 'rejected':
      return '已驳回';
    default:
      return status;
  }
}
